import{_ as o,C as n,o as l,c as s,E as i,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Moving to the United Kingdom","description":"Immigration pathways and relocation guide for the United Kingdom","frontmatter":{"layout":"doc","title":"Moving to the United Kingdom","description":"Immigration pathways and relocation guide for the United Kingdom"},"headers":[],"relativePath":"europe/united-kingdom/moving-there.md","filePath":"europe/united-kingdom/moving-there.md","lastUpdated":null}'),h={name:"europe/united-kingdom/moving-there.md"};function g(m,t,c,u,p,f){const e=n("Badge");return l(),s("div",null,[i(e,{variant:"yellow"},{default:a(()=>[...t[0]||(t[0]=[r("Points-Based System",-1)])]),_:1}),i(e,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[r("Skilled Worker Visa",-1)])]),_:1}),t[2]||(t[2]=d('<h1 id="moving-to-the-united-kingdom" tabindex="-1">Moving to the United Kingdom <a class="header-anchor" href="#moving-to-the-united-kingdom" aria-label="Permalink to &quot;Moving to the United Kingdom&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><p>The UK operates a <strong>points-based immigration system</strong> after leaving the EU. EU citizens no longer have free movement rights and must apply under the same system as other nationalities.</p><h3 id="skilled-worker-visa-most-common" tabindex="-1">Skilled Worker Visa (Most Common) <a class="header-anchor" href="#skilled-worker-visa-most-common" aria-label="Permalink to &quot;Skilled Worker Visa (Most Common)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Requirement</th><th>Details</th></tr></thead><tbody><tr><td>Job offer</td><td>From a Home Office-approved sponsor</td></tr><tr><td>Skill level</td><td>RQF Level 3 or above (A-level equivalent)</td></tr><tr><td>Salary threshold</td><td>£26,200/year (or £10.75/hour, whichever higher)</td></tr><tr><td>English language</td><td>B1 level required</td></tr><tr><td>Points needed</td><td>70 points total</td></tr><tr><td>Duration</td><td>Up to 5 years</td></tr><tr><td>Settlement</td><td>Eligible after 5 years (Indefinite Leave to Remain)</td></tr></tbody></table><p><strong>Points breakdown:</strong></p><ul><li>Job at appropriate skill level: 20 points</li><li>English language: 10 points</li><li>Salary £26,200+ or relevant PhD: 20 points</li><li>Salary above £23,580 (minimum): additional points from tradeable options</li></ul><h3 id="global-talent-visa" tabindex="-1">Global Talent Visa <a class="header-anchor" href="#global-talent-visa" aria-label="Permalink to &quot;Global Talent Visa&quot;">​</a></h3><ul><li>For leaders or potential leaders in academia, arts, culture, digital technology</li><li>No job offer required</li><li>Endorsement from recognized UK body (e.g., Royal Society, Arts Council England)</li><li>Valid for 3-5 years</li><li>Fast track to settlement (3 years)</li><li>Can be used by trans activists, researchers, academics</li></ul><h3 id="other-visa-options" tabindex="-1">Other Visa Options <a class="header-anchor" href="#other-visa-options" aria-label="Permalink to &quot;Other Visa Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Student Visa</td><td>Full-time study</td><td>University acceptance (CAS), funds proof</td><td>Duration of studies</td></tr><tr><td>Graduate Visa</td><td>After completing UK degree</td><td>Valid for 2 years (3 for PhD)</td><td>2-3 years</td></tr><tr><td>Health and Care Worker Visa</td><td>Healthcare professionals</td><td>Job offer in health or social care</td><td>Up to 5 years</td></tr><tr><td>Family Visa</td><td>Partner/family of UK resident</td><td>Relationship proof, financial requirement (£29,000+)</td><td>2.5 years, renewable</td></tr><tr><td>Innovator Founder Visa</td><td>Business creation</td><td>Endorsed business plan, funds</td><td>3 years</td></tr><tr><td>Youth Mobility Scheme</td><td>18-30 years (select countries)</td><td>Working holiday, lottery-based</td><td>2 years</td></tr></tbody></table><h3 id="eu-citizens-pre-settled-settled-status" tabindex="-1">EU Citizens (Pre-Settled / Settled Status) <a class="header-anchor" href="#eu-citizens-pre-settled-settled-status" aria-label="Permalink to &quot;EU Citizens (Pre-Settled / Settled Status)&quot;">​</a></h3><ul><li>EU citizens who lived in the UK before 31 December 2020 should have applied to the <strong>EU Settlement Scheme</strong></li><li><strong>Settled status</strong>: 5+ years continuous residence before 2021</li><li><strong>Pre-settled status</strong>: Less than 5 years</li><li>After 2021: EU citizens need a visa like everyone else</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>The UK does <strong>not</strong> have a specific digital nomad visa. Remote workers can:</p><ul><li>Enter as a <strong>Standard Visitor</strong> (up to 6 months) — but cannot work for a UK employer</li><li>Apply for a <strong>Skilled Worker Visa</strong> if employed by a UK company</li><li>Use a <strong>Global Talent Visa</strong> if eligible</li><li>Some use the <strong>Youth Mobility Scheme</strong> (age and nationality dependent)</li><li>Remote work for a non-UK company while on a visitor visa is legally unclear</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for at least 6 months</li><li>[ ] <strong>Visa</strong>: Apply well in advance (Skilled Worker: 3-8 weeks processing)</li><li>[ ] <strong>Health Surcharge</strong>: Pay Immigration Health Surcharge (£1,035/year per person)</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter</li><li>[ ] <strong>Medical Records</strong>: Relevant records</li><li>[ ] <strong>Banking</strong>: Consider opening a UK bank account from abroad</li><li>[ ] <strong>Housing</strong>: Research rental market (Rightmove, Zoopla)</li><li>[ ] <strong>Language</strong>: English — no issues for most</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] <strong>Collect Biometric Residence Permit (BRP)</strong> — within 10 days</li><li>[ ] <strong>Register with GP</strong> — Register with a local GP surgery (NHS)</li><li>[ ] <strong>National Insurance Number</strong> — Apply for NI number for work</li><li>[ ] <strong>Open bank account</strong> — Monzo, Starling, or high street bank</li><li>[ ] <strong>Get UK phone number</strong> — Giffgaff, EE, Vodafone, O2</li><li>[ ] <strong>Register with NHS Gender Identity Clinic</strong> — Put yourself on the waitlist immediately</li><li>[ ] <strong>Connect with local trans community</strong> — Stonewall, Local LGBTQ+ groups</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>London</th><th>Other Cities</th></tr></thead><tbody><tr><td>Rent (1-bedroom)</td><td>£1,500-2,500/month</td><td>£600-1,200/month</td></tr><tr><td>Groceries</td><td>£250-400/month</td><td>£200-350/month</td></tr><tr><td>Transport</td><td>£150-200/month (TfL)</td><td>£50-100/month</td></tr><tr><td>Council Tax</td><td>£100-200/month</td><td>£80-150/month</td></tr><tr><td>Utilities</td><td>£150-250/month</td><td>£120-200/month</td></tr></tbody></table><h3 id="trans-specific-considerations" tabindex="-1">Trans-Specific Considerations <a class="header-anchor" href="#trans-specific-considerations" aria-label="Permalink to &quot;Trans-Specific Considerations&quot;">​</a></h3><ul><li><strong>NHS waiting times are very long</strong> (2-5 years) — join the GIC waitlist immediately</li><li><strong>Private healthcare</strong> (GenderGP, Gendercare) is a viable option while waiting</li><li><strong>Scotland</strong> generally has better trans protections and shorter wait times</li><li><strong>Transphobia</strong> is a growing concern, particularly online and in some media</li><li><strong>London, Brighton, Manchester, Glasgow</strong> are the most trans-friendly cities</li><li><strong>Northern Ireland</strong> has the most restrictive environment</li><li><strong>Trans rights</strong> are highly politicized — monitor the political situation</li><li><strong>Equality Act 2010</strong> provides strong legal protections in theory</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li><strong>English</strong>: Spoken at all levels</li><li><strong>Regional languages</strong>: Welsh (Wales), Scots Gaelic (Scotland), Irish (NI)</li><li>No language test for most visas (except citizenship — B1 English + Life in the UK test)</li></ul><h3 id="citizenship-timeline" tabindex="-1">Citizenship Timeline <a class="header-anchor" href="#citizenship-timeline" aria-label="Permalink to &quot;Citizenship Timeline&quot;">​</a></h3><ul><li>5 years on most visas → Indefinite Leave to Remain (ILR)</li><li>12 months after ILR → Citizenship application</li><li>Life in the UK test required</li><li>B1 English language requirement</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.gov.uk/browse/visas-immigration" target="_blank" rel="noreferrer">UK Home Office - Visas</a></li><li><a href="https://www.nhs.uk/conditions/gender-dysphoria/" target="_blank" rel="noreferrer">NHS Gender Identity Services</a></li><li><a href="https://www.rightmove.co.uk/" target="_blank" rel="noreferrer">Rightmove - Housing</a></li><li><a href="https://www.stonewall.org.uk/" target="_blank" rel="noreferrer">Stonewall</a></li><li><a href="https://www.transactual.org.uk/" target="_blank" rel="noreferrer">Trans Actual UK</a></li><li><a href="https://www.gov.uk/life-in-the-uk-test" target="_blank" rel="noreferrer">UK Government - Life in the UK Test</a></li></ul>',32))])}const y=o(h,[["render",g]]);export{v as __pageData,y as default};
